import React from 'react';
import { graphql } from 'gatsby';
import { injectIntl } from 'gatsby-plugin-intl';
import { Typography } from '@material-ui/core';
import { makeStyles } from '@material-ui/core/styles';

// Components
import Layout from '../components/Layout';
import SEO from '../components/SEO';
import Impossible from '../components/SVGs/Impossible';

const useStyles = makeStyles((theme) => ({
    notFoundWrapper: {
        margin: '10px 0',
    },
    impossibleWrapper: {
        margin: '10px 0',
        width: '100%',
        height: 'auto',
        maxWidth: '700px',
    },
}));

const NotFoundPage = ({ location, intl }) => {
    const classes = useStyles();

    return (
        <Layout>
            <SEO
                lang={intl.locale}
                pathname={location?.pathname}
                robots="noindex, nofollow"
                title={intl.formatMessage({ id: 'notfound.title' })}
            />
            <div className={classes.notFoundWrapper}>
                <Typography
                    color="textPrimary"
                    variant="h4"
                >
                    {intl.formatMessage({ id: 'notfound.header' })}
                </Typography>
                <Impossible
                    className={classes.impossibleWrapper}
                />
                <Typography
                    color="textPrimary"
                >
                    {intl.formatMessage({ id: 'notfound.description' })}
                </Typography>
            </div>
        </Layout>
    );
};

export default injectIntl(NotFoundPage);

export const pageQuery = graphql`
    query {
        site {
            siteMetadata {
                title
            }
        }
    }
`;
